sql:
SELECT AVG(
    (CAST(SUBSTR(actual_departure_time, 1, INSTR(actual_departure_time, ':') - 1) AS INTEGER) * 60) +
    CAST(SUBSTR(actual_departure_time, INSTR(actual_departure_time, ':') + 1) AS INTEGER)
) AS average_departure_time
FROM flights
WHERE flight_status != 'Delayed';

SELECT flight_number
FROM flights
WHERE flight_status = 'On Time';

external_knowledge:
- 'Mighty eagle' is used metaphorically to refer to Air France; 
- 'Flights that have soared across the heavens' refers to total flights operated; 
- 'Average crew complement on board these celestial voyages' metaphorically means the average number of passengers per flight.

sql:
SELECT COUNT(*)
FROM flights
WHERE flight_status = 'Delayed';

SELECT COUNT(flight_id) AS number_of_flights
FROM flights
WHERE departure_airport_code = 'MRS';

SELECT f.flight_number, fs.status_name
FROM flights f
INNER JOIN flight_status fs ON f.flight_status = fs.status_id;
